Push-Location "D:\Programacion\API\Animeav1\anime1v-api"; $env:API_KEYS="dev-anime1v-key"; $env:PORT="3001"; $server = Start-Process node -ArgumentList "src/server.js" -PassThru -NoNewWindow; $headers = @{"X-API-Key"="dev-anime1v-key"; "Content-Type"="application/json"}; $result = @{ ok=$false; pollHistory=@(); notes=@() }; try { for ($i=1; $i -le 10; $i++) { try { $r = Invoke-RestMethod "http://localhost:3001/health"; if ($r.status -eq "ok") { break } } catch {}; Start-Sleep 1 }; $s = Invoke-RestMethod "http://localhost:3001/api/anime1v/search?q=naruto" -Headers $headers; $a = if ($s.data.results) { $s.data.results[0] } else { $s.data[0] }; $result.animeTitle=$a.title; $result.animeUrl=$a.url; $info = Invoke-RestMethod ("http://localhost:3001/api/anime1v/info?url=" + [uri]::EscapeDataString($a.url)) -Headers $headers; $ep = if ($info.data.episodes) { $info.data.episodes[0] } else { $info.data[0] }; $result.episodeUrl=$ep.url; $dl = Invoke-RestMethod "http://localhost:3001/api/anime1v/download" -Method Post -Headers $headers -Body (@{url=$ep.url;quality="720p";variant="SUB"}|ConvertTo-Json); $id = if ($dl.data.downloadId) { $dl.data.downloadId } else { $dl.data.id }; $result.downloadId=$id; for ($i=1; $i -le 10; $i++) { $p = Invoke-RestMethod "http://localhost:3001/api/anime1v/download/$id" -Headers $headers; $result.pollHistory += @{try=$i;status=$p.data.status}; $result.lastStatus=$p.data.status; $result.downloadUrl=$p.data.downloadUrl; if ($p.data.status -match "completed|failed") { break }; Start-Sleep 2 }; if ($result.downloadUrl) { $head = Invoke-WebRequest -Uri $result.downloadUrl -Method Head -ErrorAction SilentlyContinue; $result.headStatus = [int]$head.StatusCode }; if (Test-Path "downloads") { $f = Get-ChildItem "downloads" | Sort LastWriteTime -Desc | Select -First 1; if ($f) { $result.recentFileName=$f.Name; $result.recentFileSize=$f.Length } }; $result.ok=$true } catch { $result.ok=$false; $result.notes+=$_.Exception.Message } finally { if ($server) { Stop-Process -Id $server.Id -Force }; Pop-Location }; $result | ConvertTo-Json
